if let existingInterceptor = mutableState.interceptor {
    if let existingInterceptor = existingInterceptor as? Interceptor {
        // Only Interceptor should be at the root.
        mutableState.interceptor = Interceptor(adapters: existingInterceptor.adapters + [adapter],
                                               retriers: existingInterceptor.retriers)
    } else {
        // Somehow we have a different root interceptor, split it back up.
        mutableState.interceptor = Interceptor(adapters: [adapter], interceptors: [existingInterceptor])
    }
} else {
    mutableState.interceptor = Interceptor(adapters: [adapter])
}

if let existingInterceptor = mutableState.interceptor {
    if let existingInterceptor = existingInterceptor as? Interceptor {
        // Only Interceptor should be at the root.
        mutableState.interceptor = Interceptor(adapters: existingInterceptor.adapters,
                                               retriers: existingInterceptor.retriers + [retrier])
    } else {
        // Somehow we have a different root interceptor, split it back up.
        mutableState.interceptor = Interceptor(retriers: [retrier], interceptors: [existingInterceptor])
    }
} else {
    mutableState.interceptor = Interceptor(retriers: [retrier])
}

do {
    let adaptedRequest = try result.get()
    try adaptedRequest.validate()

    self.rootQueue.async { request.didAdaptInitialRequest(initialRequest, to: adaptedRequest) }

    guard shouldCreateTask() else { return }

    self.rootQueue.async { self.didCreateURLRequest(adaptedRequest, for: request) }
} catch {
    self.rootQueue.async { request.didFailToAdaptURLRequest(initialRequest, withError: .requestAdaptationFailed(error: error)) }
}

if let request = request(for: dataTask, as: DataRequest.self) {
    request.didReceiveResponse(response, completionHandler: completionHandler)
} else if let request = request(for: dataTask, as: DataStreamRequest.self) {
    request.didReceiveResponse(response, completionHandler: completionHandler)
} else {
    assertionFailure("dataTask did not find DataRequest or DataStreamRequest in didReceive response")
    completionHandler(.allow)
    return
}

guard let (credential, credentialVersion): (Credential, Int) = mutableState.read({ mutableState in
            if let credential = mutableState.credential {
                (credential, mutableState.credentialVersion)
            } else {
                nil
            }
        }) else {
            let error = AuthenticationError.missingCredential
            completion(.doNotRetryWithError(error))
            return
        }

switch mutableState.refreshState {
case let .failed(refreshError):
    // A refresh was already attempted and failed for this credential version.
    // Do not queue and do not trigger another refresh.
    return .doNotRetryWithError(refreshError)
case .refreshing:
    mutableState.requestsToRetry.append(completion)
    return nil
case .idle:
    mutableState.requestsToRetry.append(completion)
    refresh(credential, for: session, insideLock: &mutableState)
    return nil
}

while inputStream.hasBytesAvailable {
    var buffer = [UInt8](repeating: 0, count: streamBufferSize)
    let bytesRead = inputStream.read(&buffer, maxLength: streamBufferSize)

    if let error = inputStream.streamError {
        throw AFError.multipartEncodingFailed(reason: .inputStreamReadFailed(error: error))
    }

    if bytesRead > 0 {
        encoded.append(buffer, count: bytesRead)
    } else {
        break
    }
}

while bytesToWrite > 0, outputStream.hasSpaceAvailable {
    let bytesWritten = outputStream.write(buffer, maxLength: bytesToWrite)

    if let error = outputStream.streamError {
        throw AFError.multipartEncodingFailed(reason: .outputStreamWriteFailed(error: error))
    }

    bytesToWrite -= bytesWritten

    if bytesToWrite > 0 {
        buffer = Array(buffer[bytesWritten..<buffer.count])
    }
}

guard var data, !data.isEmpty else {
    guard emptyResponseAllowed(forRequest: request, response: response) else {
        throw AFError.responseSerializationFailed(reason: .inputDataNilOrZeroLength)
    }

    guard let emptyResponseType = T.self as? any EmptyResponse.Type, let emptyValue = emptyResponseType.emptyValue() as? T else {
        throw AFError.responseSerializationFailed(reason: .invalidEmptyResponse(type: "\(T.self)"))
    }

    return emptyValue
}

switch command {
case let helpCommand as HelpCommand:
  throw ParserError.helpRequested(visibility: helpCommand.visibility)
case let result as _WrappedParsableCommand<Self>:
  return result.options
case var result as Self:
  do {
    try result.validate()
  } catch {
    throw ParserError.userValidationError(error)
  }
  return result
default:
  // TODO: this should be a "wrong command" message
  throw ParserError.invalidState
}

if case .argumentIndex(let index) = originElement,
      index.subIndex != .complete,
      let originalInput =
        inputArguments
        .originalInput(at: .argumentIndex(index.completeIndex))
    {
      let completeName = Name(originalInput[...])
      return ParserError.missingValueOrUnknownCompositeOption(
        InputOrigin(element: originElement), parsed.name, completeName)
    } else {
      return ParserError.missingValueForOption(
        InputOrigin(element: originElement), parsed.name)
    }

if let equalIdx = remainder.firstIndex(of: "=") {
  let name = remainder[remainder.startIndex..<equalIdx]
  guard !name.isEmpty else {
    throw ParserError.invalidOption(makeName(remainder).synopsisString)
  }
  let after = remainder.index(after: equalIdx)
  let value = String(remainder[after..<remainder.endIndex])
  self = .nameWithValue(makeName(name), value)
} else {
  self = .name(makeName(remainder))
}

do {
  let _ = try type.init(from: Validator(argumentKeys: argumentKeys))
  return InvalidDecoderError(type: type)
} catch let result as Validator.ValidationResult {
  switch result {
  case .missingCodingKeys(let keys):
    return MissingKeysError(missingCodingKeys: keys)
  case .success:
    return nil
  }
} catch {
  fatalError("Unexpected validation error: \(error)")
}

while true {
  let c = Swift.max(producer.underestimatedCount, self.freeCapacity)
  try self.append(addingCount: c) { target throws(E) in
    while !target.isFull {
      guard try producer.generate(into: &target) else { return }
    }
  }
  // Nudge the container to resize itself, providing more `freeCapacity` in
  // the next iteration. Doing this separately avoids forcing the container
  // to unnecessarily reallocate itself when the producer is already
  // complete. (In exchange, we have to move a handful of items twice.)
  guard let next = try producer.next() else { return }
  self.append(next)
}

if contents.count > 0 {
  contents.withUnsafeBufferPointer { source in
    storage.update { target in
      let segments = target.mutableSegments()
      let c = segments.first.count
      segments.first.initializeAll(fromContentsOf: source.prefix(c))
      if let second = segments.second {
        second.initializeAll(fromContentsOf: source.dropFirst(c))
      }
    }
  }
}

for (bucket, slot) in $0.childMap {
  let branch = try $0[child: slot].filter(level.descend(), isIncluded)
  if let branch = branch {
    assert(branch.count < self.count)
    if !removing {
      removing = true
      result.copyItemsAndChildren(level, from: $0, upTo: bucket)
    }
    result.addNewChildBranch(level, branch, at: bucket)
  } else if removing {
    result.addNewChildNode(level, $0[child: slot], at: bucket)
  }
}

if other.isCollisionNode {
  return read { l in
    guard level.isAtRoot, l.hasSingletonItem else { return false }
    // Annoying special case: the root node may contain a single item
    // that matches one in the collision node.
    return other.read { r in
      let hash = _Hash(l[item: .zero].key)
      return r.find(level, l[item: .zero].key, hash) != nil
    }
  }
}

while !container.isAtEnd {
  let key = try container.decode(Key.self)

  guard !container.isAtEnd else {
    throw DecodingError.dataCorrupted(
      DecodingError.Context(
        codingPath: decoder.codingPath,
        debugDescription: "Unkeyed container reached end before value in key-value pair."
      )
    )
  }

  let value = try container.decode(Value.self)
  self[key] = value
}

while !container.isAtEnd {
  let element = try container.decode(Element.self)
  let inserted = self._insert(element)
  guard inserted else {
    let context = DecodingError.Context(
      codingPath: container.codingPath,
      debugDescription: "Decoded elements aren't unique (first duplicate at offset \(self.count))")
    throw DecodingError.dataCorrupted(context)
  }
}

while !container.isAtEnd {
  let element = try container.decode(Element.self)
  guard previousElement == nil || previousElement! < element else {
    let context = DecodingError.Context(
      codingPath: container.codingPath,
      debugDescription: "Decoded elements out of order.")
    throw DecodingError.dataCorrupted(context)
  }
  builder.append(element)
  previousElement = element
}

do throws(E) {
  let result = try body(&tailAllocated)

  // Tell the tail-allocated buffer not to free the storage.
  let finalPointer = tailAllocated.leakStorage()
  precondition(finalPointer == pointer)

  return .success(result)
} catch {
  // Tell the tail-allocated buffer not to free the storage.
  let finalPointer = tailAllocated.leakStorage()
  precondition(finalPointer == pointer)

  return .failure(error)
}

do {
    for try await chunk in chunks {
        bytesWritten += try await self.write(contentsOf: chunk)
    }
} catch let error as FileSystemError {
    // From call to 'write'.
    throw error
} catch let error {
    // From iterating the async sequence.
    throw FileSystemError(
        code: .unknown,
        message: "AsyncSequence of bytes threw error while writing to the buffered writer.",
        cause: error,
        location: .here()
    )
}

if let errno = error as? Errno {
    switch errno {
    case .badFileDescriptor:
        code = .closed
        message = "Unable to duplicate descriptor of closed handle for '\(path)'."
    default:
        code = .unknown
        message = "Unable to duplicate descriptor of handle for '\(path)'."
    }
    cause = SystemCallError(systemCall: "dup", errno: errno)
} else {
    code = .unknown
    message = "Unable to duplicate descriptor of handle for '\(path)'."
    cause = error
}

guard maxDescriptors >= Self.minDescriptorsAllowed else {
    // 2 is not quite the same as sequential, you could have two concurrent directory
    // listings for example less than 2 and you can't actually do a _copy_ though so it's
    // non-sensical.
    throw FileSystemError(
        code: .invalidArgument,
        message: "Can't do a copy operation without at least 2 file descriptors '\(maxDescriptors)' is illegal",
        cause: nil,
        location: .here()
    )
}

switch self.state {
case .error:
    // We failed any outstanding promises when we entered the error state and will fail any
    // new promises in write.
    assert(self.promiseBuffer.count == 0)
case .operational:
    let promiseBuffer = self.promiseBuffer
    self.promiseBuffer.removeAll()
    for promise in promiseBuffer {
        promise.fail(ChannelError.eof)
    }
}
